@tool
def extract_iocs(email_content: str) -> str:
    """Extract indicators of compromise (URLs, IPs, domains, hashes) from email content."""
    urls   = re.findall(r'https?://[^\s"<>]+', email_content)
    ips    = re.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b', email_content)
    hashes = re.findall(r'\b[0-9a-f]{32,64}\b', email_content, re.I)
    return json.dumps({"urls": urls[:20], "ips": ips[:10], "hashes": hashes[:5]})

