# Example: integrating with Splunk REST API and XSOAR (Cortex) SOAR
import httpx

class SplunkClient:
    def __init__(self, base_url: str, token: str):
        self.base_url = base_url
        self.headers = {"Authorization": f"Splunk {token}"}

    def search(self, spl_query: str, earliest: str = "-24h") -> list[dict]:
        """Run a Splunk SPL search and return events."""
        # 1. Create the search job
        resp = httpx.post(
            f"{self.base_url}/services/search/jobs",
            data={"search": f"search {spl_query}", "earliest_time": earliest,
                  "output_mode": "json"},
            headers=self.headers, verify=False,
        )
        job_id = resp.json()["sid"]

        # 2. Poll until done
        import time
        for _ in range(30):
            status_resp = httpx.get(
                f"{self.base_url}/services/search/jobs/{job_id}",
                params={"output_mode": "json"}, headers=self.headers, verify=False,
            )
            if status_resp.json()["entry"][0]["content"]["isDone"]:
                break
            time.sleep(1)

        # 3. Retrieve results
        results_resp = httpx.get(
            f"{self.base_url}/services/search/jobs/{job_id}/results",
            params={"output_mode": "json", "count": 100},
            headers=self.headers, verify=False,
        )
        return results_resp.json().get("results", [])

class XSOARClient:
    def __init__(self, base_url: str, api_key: str):
        self.base_url = base_url
        self.headers = {"x-xdr-auth-id": "1", "x-xdr-nonce": "...", "Authorization": api_key}

    def create_incident(self, name: str, severity: int, details: str) -> dict:
        """Create an incident in Cortex XSOAR. severity: 1=Low, 2=Medium, 3=High, 4=Critical."""
        resp = httpx.post(
            f"{self.base_url}/incident",
            json={"name": name, "severity": severity, "details": details,
                  "type": "Network", "owner": "agent-soc"},
            headers=self.headers,
        )
        resp.raise_for_status()
        return resp.json()
